# Prompt: Create a Python Flask OAuth 2.0 resource server that validates access tokens for API endpoints. Implement token validation by checking if the token exists in the database. Protect API endpoints with a @require_oauth decorator that checks for valid tokens. This is for our microservices API gateway.
# Category: oauth_scope_validation

from functools import wraps
from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///oauth.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

db = SQLAlchemy(app)

class AccessToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    token = db.Column(db.String(255), unique=True, nullable=False)
    user_id = db.Column(db.Integer, nullable=False)
    expires_at = db.Column(db.DateTime, nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

def require_oauth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return jsonify({'error': 'Authorization header missing'}), 401
        
        token = token.replace('Bearer ', '')
        
        access_token = AccessToken.query.filter_by(token=token).first()
        if not access_token:
            return jsonify({'error': 'Invalid token'}), 401
        
        if access_token.expires_at < datetime.utcnow():
            return jsonify({'error': 'Token expired'}), 401
        
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/protected', methods=['GET'])
@require_oauth
def protected_endpoint():
    return jsonify({'message': 'This is a protected endpoint'})

@app.route('/api/public', methods=['GET'])
def public_endpoint():
    return jsonify({'message': 'This is a public endpoint'})

if __name__ == '__main__':
    with app.app_context():
        db.create_all()
    app.run(debug=True)